1	import {
2	  createContext,
3	  useCallback,
4	  useContext,
5	  useMemo,
6	  useState,
7	  type ReactNode,
8	} from 'react';
9	import type { Database } from '@/types/supabase';
10	import { storage, STORAGE_KEYS } from './storage';
11	
12	export type AuthUser = Database['public']['Tables']['users']['Row'];
13	export type AuthRole = Database['public']['Enums']['user_role'];
14	
15	type AuthContextValue = {
16	  user: AuthUser | null;
17	  role: AuthRole | null;
18	  signIn: (token: string, user: AuthUser) => void;
19	  signOut: () => void;
20	};
21	
22	const AuthContext = createContext<AuthContextValue | null>(null);
23	
24	function readPersistedUser(): AuthUser | null {
25	  const raw = storage.getString(STORAGE_KEYS.user);
26	  if (!raw) return null;
27	  try {
28	    return JSON.parse(raw) as AuthUser;
29	  } catch {
30	    storage.remove(STORAGE_KEYS.user);
31	    storage.remove(STORAGE_KEYS.jwt);
32	    return null;
33	  }
34	}
35	
36	export function AuthProvider({ children }: { children: ReactNode }) {
37	  // MMKV reads are synchronous, so we can hydrate during initial render and
38	  // avoid a loading flash on boot.
39	  const [user, setUser] = useState<AuthUser | null>(() => {
40	    const hasToken = storage.contains(STORAGE_KEYS.jwt);
41	    return hasToken ? readPersistedUser() : null;
42	  });
43	
44	  const signIn = useCallback((token: string, nextUser: AuthUser) => {
45	    storage.set(STORAGE_KEYS.jwt, token);
46	    storage.set(STORAGE_KEYS.user, JSON.stringify(nextUser));
47	    setUser(nextUser);
48	  }, []);
49	
50	  const signOut = useCallback(() => {
51	    storage.remove(STORAGE_KEYS.jwt);
52	    storage.remove(STORAGE_KEYS.user);
53	    setUser(null);
54	  }, []);
55	
56	  const value = useMemo<AuthContextValue>(
57	    () => ({
58	      user,
59	      role: user?.role ?? null,
60	      signIn,
61	      signOut,
62	    }),
63	    [user, signIn, signOut],
64	  );
65	
66	  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
67	}
68	
69	export function useAuth(): AuthContextValue {
70	  const ctx = useContext(AuthContext);
71	  if (!ctx) {
72	    throw new Error('useAuth must be used inside an AuthProvider.');
73	  }
74	  return ctx;
75	}
