1	import { useEffect } from 'react';
2	import { Slot } from 'expo-router';
3	import { GestureHandlerRootView } from 'react-native-gesture-handler';
4	import { StatusBar } from 'expo-status-bar';
5	import { useFonts } from 'expo-font';
6	import * as SplashScreen from 'expo-splash-screen';
7	import { fontAssets } from '@/design/typography';
8	import { ToastProvider } from '@/components/primitives/Toast';
9	import { AuthProvider } from '@/lib/auth';
10	
11	// Hold the splash screen until custom fonts register — text with an unregistered
12	// fontFamily silently falls back to System on iOS and the swap is visible to the user.
13	// Promise rejects if the splash was already dismissed (fast-refresh, dev reloads) —
14	// swallow so Metro doesn't see an unhandled rejection.
15	SplashScreen.preventAutoHideAsync().catch(() => {});
16	
17	export default function RootLayout() {
18	  const [fontsLoaded, fontError] = useFonts(fontAssets);
19	
20	  useEffect(() => {
21	    if (fontsLoaded || fontError) {
22	      SplashScreen.hideAsync();
23	    }
24	  }, [fontsLoaded, fontError]);
25	
26	  if (!fontsLoaded && !fontError) {
27	    return null;
28	  }
29	
30	  return (
31	    <GestureHandlerRootView style={{ flex: 1 }}>
32	      <AuthProvider>
33	        <ToastProvider>
34	          <Slot />
35	        </ToastProvider>
36	      </AuthProvider>
37	      <StatusBar style="auto" />
38	    </GestureHandlerRootView>
39	  );
40	}
